import ToolLayout from '../../layouts/ToolLayout.astro';
import ToolShell from '../../components/ToolShell.astro';
import ToolWidget from '../../components/tools/ToolWidget.astro';
import tools from '../../data/tools.json';
import trends from '../../data/trends.json';

export function getStaticPaths() {
  return tools.map((tool) => ({ params: { slug: tool.slug } }));
}

const { slug } = Astro.params;
const tool = tools.find((t) => t.slug === slug);

if (!tool) {
  throw new Error(`Tool not found: ${slug}`);
}

const relatedTrend = tool.relatedTrend
  ? trends.find((t) => t.slug === tool.relatedTrend)
  : null;

const backHref = relatedTrend ? `/trends/${relatedTrend.slug}` : '/tools';
const backLabel = relatedTrend ? 'Back to guide' : 'All tools';
---

<ToolLayout
  title={tool.title}
  description={tool.description}
