import Layout from '../../layouts/Layout.astro';
import TrendCard from '../../components/TrendCard.astro';
import ToolLauncher from '../../components/ToolLauncher.astro';
import ToolModal from '../../components/ToolModal.astro';
import trends from '../../data/trends.json';
import tools from '../../data/tools.json';
import { AFFILIATE_DISCLOSURE, CATEGORIES, formatDate, SITE } from '../../lib/site';

export function getStaticPaths() {
  return trends.map((trend) => ({ params: { slug: trend.slug } }));
}

const { slug } = Astro.params;
const trend = trends.find((t) => t.slug === slug);

if (!trend) {
  throw new Error(`Trend not found: ${slug}`);
}

const relatedTool = trend.relatedTool
  ? tools.find((t) => t.slug === trend.relatedTool)
  : null;

const modalSlugs = relatedTool ? [relatedTool.slug] : [];
---

<Layout
  title={trend.title}
  description={trend.summary}
  keywords={trend.keywords}
  type="article"
  published={trend.updated}
>
  <article class="prose guide-article">
    <div class="guide-meta">
      <span class="badge">{CATEGORIES[trend.category] ?? trend.category}</span>
      {trend.status === 'hot' && <span class="badge">🔥 Trending</span>}
    </div>
    <h1>{trend.title}</h1>
    <p class="muted">Updated {formatDate(trend.updated)} · US market</p>

    <p class="guide-lead">{trend.summary}</p>

    <div class="disclosure">{AFFILIATE_DISCLOSURE}</div>

    <h2>Why it's trending</h2>
    <p>{trend.whyHot}</p>

    <h2>Who this is for</h2>
    <ul>
      {trend.whoItsFor.map((item) => <li>{item}</li>)}
    </ul>

    <h2>Who should skip</h2>
    <ul>
      {trend.whoShouldSkip.map((item) => <li>{item}</li>)}
    </ul>

    <h2>Before you buy</h2>
    <ul>
      {trend.buyerPitfalls.map((item) => <li>{item}</li>)}
    </ul>

    <h2>Our top picks</h2>
    <div class="product-list">
      {
        trend.products.map((product) => (
          <div class="product">
            <div class="tag">{product.tag}</div>
            <h3>{product.name}</h3>
            <p class="muted">Typical price: {product.price}</p>
            <p><strong>Pros:</strong> {product.pros.join(' · ')}</p>
            <p><strong>Cons:</strong> {product.cons.join(' · ')}</p>
            <a class="btn" href={product.affiliateUrl} rel="nofollow sponsored" target="_blank">
              View pricing →
            </a>
          </div>
        ))
      }
    </div>

    {
      relatedTool && (
        <>
          <h2>Helpful tool</h2>
          <p class="muted">Quick check while you read — or open the full tool page to bookmark for later.</p>
          <ToolLauncher slug={relatedTool.slug} />
        </>
      )
    }
  </article>

  {modalSlugs.length > 0 && <ToolModal slugs={modalSlugs} />}
</Layout>

<script>
  import '../../scripts/tool-widgets.ts';
</script>

